// src/components/recipes/RecipeCategorySelector.jsx
import React, { useState, useEffect } from 'react'
import { useLanguage } from '../../context/LanguageContext'
import { translations } from '../../translations/translations'
import LanguageSelector from '../LanguageSelector'

const DS = {
  color: {
    bg: '#ECEEED', surface: '#FFFFFF', surfaceAlt: '#F7F9F8',
    primary: '#1B5E37', primaryGlow: 'rgba(27,94,55,0.08)',
    cardHeader: '#E8F5EE',
    graphite: '#1E2A26', graphiteMed: '#3D4F48', graphiteLight: '#6B7D76', graphiteMuted: '#95A39D',
    border: '#D5DDD9', borderLight: '#E4EBE7',
  },
  font: "'DM Sans', system-ui, sans-serif",
  radius: '0px',
  shadow: { sm: '0 1px 3px rgba(30,42,38,0.06),0 1px 2px rgba(30,42,38,0.04)' },
}
const LOGO = 'https://aladinfoods.bg/assets/images/aladinfoods_logo.png'
const CSS = `@import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&display=swap');*,*::before,*::after{box-sizing:border-box}body{margin:0;background:${DS.color.bg}}@keyframes cf{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}@media(max-width:767px){input,button,select,textarea{font-size:16px!important}}`

const backIcon = (c) => <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={c} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M15 18l-6-6 6-6"/></svg>

const CATEGORY_ICONS = {
  'duner': 'data:image/png;base64,',
  'pizza': 'data:image/png;base64,',
  'chicken': 'data:image/png;base64,',
  'sides': 'data:image/png;base64,',
  'new-products': 'data:image/png;base64,',
  'promotions': 'data:image/png;base64,',
  'packaging': 'data:image/png;base64,',
}

const CAT_COLOR = '#166534'
const CAT_BG = '#E8F5EE'

const useR = () => { const [w, sW] = useState(window.innerWidth); useEffect(() => { const h = () => sW(window.innerWidth); window.addEventListener('resize', h); return () => window.removeEventListener('resize', h) }, []); return w < 768 }

const RecipeCategorySelector = ({ onSelectCategory, onBack }) => {
  const { currentLanguage } = useLanguage()
  const t = translations[currentLanguage]
  const mob = useR()
  const pad = mob ? '12px' : '20px'
  const [hoverId, setHoverId] = useState(null)
  const [hoverBack, setHoverBack] = useState(false)

  const categories = [
    { id: 'duner', name: t.duner, description: t.dunerDesc },
    { id: 'pizza', name: t.pizza, description: t.pizzaDesc },
    { id: 'chicken', name: t.chicken, description: t.chickenDesc },
    { id: 'sides', name: t.sides, description: t.sidesDesc },
    { id: 'new-products', name: t.newProducts, description: t.newProductsDesc },
    { id: 'promotions', name: t.promotions, description: t.promotionsDesc },
    { id: 'packaging', name: t.packaging, description: t.packagingDesc },
  ]

  return (<><style>{CSS}</style>
    <div style={{ minHeight: '100vh', backgroundColor: DS.color.bg, fontFamily: DS.font, color: DS.color.graphite, display: 'flex', flexDirection: 'column' }}>

      {/* DARK TOP BAR */}
      <div style={{ position: 'sticky', top: 0, zIndex: 100, backgroundColor: DS.color.graphite, padding: '0 16px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', height: '48px', boxShadow: '0 2px 8px rgba(0,0,0,0.2)' }}>
        <button
          onClick={onBack}
          onMouseEnter={() => setHoverBack(true)}
          onMouseLeave={() => setHoverBack(false)}
          style={{
            display: 'flex', alignItems: 'center', gap: '6px', padding: '6px 12px',
            backgroundColor: hoverBack ? 'rgba(255,255,255,0.12)' : 'rgba(255,255,255,0.06)',
            border: '1px solid rgba(255,255,255,0.08)', borderRadius: DS.radius,
            cursor: 'pointer', color: '#fff', fontFamily: DS.font, fontSize: '12px', fontWeight: 600,
            transition: 'all 0.15s',
          }}
        >
          {backIcon('#fff')} {t.backToDashboard}
        </button>
        <LanguageSelector />
      </div>

      <div style={{ maxWidth: '1200px', margin: '0 auto', padding: pad, flex: 1, width: '100%' }}>

        {/* LOGO + TITLE */}
        <div style={{ display: 'flex', alignItems: 'center', gap: mob ? '10px' : '14px', marginBottom: '20px' }}>
          <img src={LOGO} alt="Aladin Foods" style={{ height: mob ? '36px' : '48px', objectFit: 'contain', flexShrink: 0 }} onError={e => { e.target.style.display = 'none' }} />
          <div>
            <h1 style={{ fontSize: mob ? '16px' : '22px', fontWeight: 700, color: DS.color.primary, margin: 0, letterSpacing: '-0.01em', lineHeight: 1.2, textTransform: 'uppercase', fontFamily: DS.font }}>{t.recipesAladinFoods}</h1>
            <p style={{ fontFamily: DS.font, fontSize: mob ? '10px' : '12px', color: DS.color.graphiteLight, fontWeight: 500, margin: '3px 0 0' }}>{t.selectCategory}</p>
          </div>
        </div>

        {/* CATEGORY CARDS GRID */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: mob ? 'repeat(2, 1fr)' : 'repeat(auto-fit, minmax(260px, 1fr))',
          gap: mob ? '8px' : '14px',
        }}>
          {categories.map((category) => {
            const isHov = hoverId === category.id
            return (
              <div
                key={category.id}
                onClick={() => onSelectCategory(category.id)}
                onMouseEnter={() => setHoverId(category.id)}
                onMouseLeave={() => setHoverId(null)}
                style={{
                  backgroundColor: DS.color.surface,
                  borderRadius: DS.radius,
                  boxShadow: isHov ? `0 12px 28px ${CAT_COLOR}30` : DS.shadow.sm,
                  padding: mob ? '16px 12px' : '24px',
                  cursor: 'pointer',
                  transition: 'all 0.2s ease',
                  border: isHov ? `2px solid ${CAT_COLOR}` : `1px solid ${DS.color.borderLight}`,
                  textAlign: 'center',
                  transform: isHov ? 'translateY(-6px)' : 'translateY(0)',
                  animation: 'cf 0.4s ease',
                }}
              >
                {/* Icon */}
                <div style={{
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  margin: `0 auto ${mob ? '10px' : '16px'} auto`,
                  transition: 'all 0.2s',
                  transform: isHov ? 'scale(1.08)' : 'scale(1)',
                }}>
                  <img src={CATEGORY_ICONS[category.id]} alt={category.name} style={{ width: mob ? '48px' : '64px', height: mob ? '48px' : '64px', objectFit: 'contain' }} />
                </div>

                <h3 style={{
                  margin: `0 0 ${mob ? '4px' : '8px'} 0`,
                  fontFamily: DS.font,
                  fontSize: mob ? '14px' : '18px',
                  color: CAT_COLOR,
                  fontWeight: 700,
                }}>
                  {category.name}
                </h3>

                <p style={{
                  margin: 0,
                  fontFamily: DS.font,
                  color: DS.color.graphiteLight,
                  fontSize: mob ? '10px' : '13px',
                  lineHeight: 1.5,
                }}>
                  {category.description}
                </p>
              </div>
            )
          })}
        </div>
      </div>

      {/* FOOTER */}
      <div style={{ textAlign: 'center', padding: mob ? '16px 12px' : '20px 24px', color: DS.color.graphiteMuted, fontFamily: DS.font, fontSize: '11px', fontWeight: 500, borderTop: `1px solid ${DS.color.borderLight}`, marginTop: 'auto' }}>© 2026 Aladin Foods | by MG</div>
    </div></>)
}

export default RecipeCategorySelector